--
-- Table structure for table `invest_assets`
--

DROP TABLE IF EXISTS `invest_assets`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `invest_assets` (
  `id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `organization_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `asset_ticker` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `asset_type` enum('stock','option_call','option_put','fii','fixed_income','alternative','artwork','real_estate','cash') COLLATE utf8mb4_unicode_ci NOT NULL,
  `current_quantity` decimal(18,4) DEFAULT '0.0000',
  `managerial_avg_price` decimal(18,4) DEFAULT '0.0000',
  `metadata` json DEFAULT NULL,
  `status` enum('active','liquidated') COLLATE utf8mb4_unicode_ci DEFAULT 'active',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `org_asset_idx` (`organization_id`,`asset_ticker`),
  CONSTRAINT `invest_assets_ibfk_1` FOREIGN KEY (`organization_id`) REFERENCES `organizations` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

