--
-- Table structure for table `invest_daily_snapshots`
--

DROP TABLE IF EXISTS `invest_daily_snapshots`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `invest_daily_snapshots` (
  `id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `organization_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `asset_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `snapshot_date` date NOT NULL,
  `closing_price` decimal(18,4) NOT NULL,
  `quantity_held` decimal(18,4) NOT NULL,
  `managerial_avg_price` decimal(18,4) NOT NULL,
  `total_market_value` decimal(18,4) NOT NULL,
  `total_managerial_value` decimal(18,4) NOT NULL,
  `unrealized_pnl` decimal(18,4) NOT NULL,
