--
-- Table structure for table `invest_ledger_entries`
--

DROP TABLE IF EXISTS `invest_ledger_entries`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `invest_ledger_entries` (
  `id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `organization_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `asset_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `underlying_ticker` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `transaction_date` date NOT NULL,
  `transaction_type` enum('buy','sell','dividend','jcp','split','bonus','option_exercise','fee','revaluation','opening_balance','put_sell','put_buy','call_sell','call_buy','securities_lending','capital_deposit','capital_withdrawal','cash_yield','penalty_b3','pending_settlement') COLLATE utf8mb4_unicode_ci NOT NULL,
  `quantity` decimal(18,4) NOT NULL,
  `unit_price` decimal(18,4) NOT NULL,
  `total_gross_value` decimal(18,4) NOT NULL,
  `brokerage_fee` decimal(18,4) DEFAULT '0.0000',
  `b3_fees` decimal(18,4) DEFAULT '0.0000',
  `irrf_tax` decimal(18,4) DEFAULT '0.0000',
  `total_net_value` decimal(18,4) NOT NULL,
  `impacts_managerial_price` tinyint(1) DEFAULT '1',
  `notes` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `broker_note_ref` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `source_batch_id` varchar(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `asset_id` (`asset_id`),
  KEY `idx_invest_ledger_org_date` (`organization_id`,`transaction_date`),
  CONSTRAINT `invest_ledger_entries_ibfk_1` FOREIGN KEY (`organization_id`) REFERENCES `organizations` (`id`),
  CONSTRAINT `invest_ledger_entries_ibfk_2` FOREIGN KEY (`asset_id`) REFERENCES `invest_assets` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

