DROP TABLE IF EXISTS `telemetry_events`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `telemetry_events` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `organization_id` varchar(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `contract_id` varchar(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `role_id` varchar(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `user_role_id` varchar(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `impersonator_user_id` varchar(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `event_type` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `event_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL,
  `module_code` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `screen_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `session_id` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `metadata` json DEFAULT NULL,
  `ip_address` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `user_agent` text COLLATE utf8mb4_unicode_ci,
  `client_timestamp` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_telemetry_org` (`organization_id`),
  KEY `idx_telemetry_user` (`user_id`),
  KEY `idx_telemetry_contract` (`contract_id`),
  KEY `idx_telemetry_event` (`event_type`,`event_name`),
  KEY `idx_telemetry_created` (`created_at`),
  KEY `idx_telemetry_session` (`session_id`)
) ENGINE=InnoDB AUTO_INCREMENT=578 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
